CREATE TABLE kf_users (id SERIAL PRIMARY KEY, username VARCHAR(64) NOT NULL UNIQUE, display_name VARCHAR(128), avatar_url TEXT, telegram_id BIGINT UNIQUE, telegram_username VARCHAR(64), role VARCHAR(16) NOT NULL DEFAULT 'user', is_banned BOOLEAN NOT NULL DEFAULT FALSE, is_muted BOOLEAN NOT NULL DEFAULT FALSE, ban_reason TEXT, mute_until TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());